// ============================================
// Generated by SparseTensorCompiler
// Kernel: spmv
// Format-correctness reordering: not needed
// Optimization: interchange=OFF
// Optimization: blocking=ON (size=32)
// ============================================

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>

// ============================================
// CSRMatrix Structure (also used for CSC)
// ============================================

typedef struct {
    int rows;
    int cols;
    int nnz;
    // CSR fields
    int* row_ptr;
    int* col_idx;
    // CSC fields (same memory, different interpretation)
    int* col_ptr;  // Same as row_ptr for CSC
    int* row_idx;  // Same as col_idx for CSC
    double* vals;
} CSRMatrix;

// ============================================
// Matrix Market Loader (COO -> CSR)
// ============================================

CSRMatrix* load_matrix_market(const char* filename) {
    FILE* f = fopen(filename, "r");
    if (!f) {
        fprintf(stderr, "Error: Cannot open file %s\n", filename);
        return NULL;
    }

    // Skip comments and read header
    char line[1024];
    while (fgets(line, sizeof(line), f)) {
        if (line[0] != '%') break;
    }

    // Parse dimensions
    int rows, cols, nnz;
    sscanf(line, "%d %d %d", &rows, &cols, &nnz);

    // Allocate COO arrays
    int* coo_row = (int*)malloc(nnz * sizeof(int));
    int* coo_col = (int*)malloc(nnz * sizeof(int));
    double* coo_val = (double*)malloc(nnz * sizeof(double));

    // Read COO entries (1-indexed in file, convert to 0-indexed)
    for (int i = 0; i < nnz; i++) {
        int r, c;
        double v;
        if (fscanf(f, "%d %d %lf", &r, &c, &v) != 3) {
            // Try pattern matrix (no values)
            fseek(f, 0, SEEK_SET);
            while (fgets(line, sizeof(line), f)) {
                if (line[0] != '%') break;
            }
            for (int j = 0; j < nnz; j++) {
                fscanf(f, "%d %d", &coo_row[j], &coo_col[j]);
                coo_row[j]--;  // Convert to 0-indexed
                coo_col[j]--;
                coo_val[j] = 1.0;  // Pattern matrix
            }
            break;
        }
        coo_row[i] = r - 1;  // Convert to 0-indexed
        coo_col[i] = c - 1;
        coo_val[i] = v;
    }
    fclose(f);

    // Convert COO to CSR (row-major)
    CSRMatrix* mat = (CSRMatrix*)malloc(sizeof(CSRMatrix));
    mat->rows = rows;
    mat->cols = cols;
    mat->nnz = nnz;
    mat->row_ptr = (int*)calloc(rows + 1, sizeof(int));
    mat->col_idx = (int*)malloc(nnz * sizeof(int));
    mat->vals = (double*)malloc(nnz * sizeof(double));
    // CSC aliases (point to same memory as CSR)
    mat->col_ptr = mat->row_ptr;
    mat->row_idx = mat->col_idx;

    // Count nnz per row
    for (int i = 0; i < nnz; i++) {
        mat->row_ptr[coo_row[i] + 1]++;
    }

    // Cumulative sum to get row_ptr
    for (int i = 0; i < rows; i++) {
        mat->row_ptr[i + 1] += mat->row_ptr[i];
    }

    // Fill col_idx and vals
    int* row_counters = (int*)calloc(rows, sizeof(int));
    for (int i = 0; i < nnz; i++) {
        int row = coo_row[i];
        int dest = mat->row_ptr[row] + row_counters[row];
        mat->col_idx[dest] = coo_col[i];
        mat->vals[dest] = coo_val[i];
        row_counters[row]++;
    }

    // Cleanup
    free(coo_row);
    free(coo_col);
    free(coo_val);
    free(row_counters);

    return mat;
}

void free_csr(CSRMatrix* mat) {
    if (mat) {
        free(mat->row_ptr);
        free(mat->col_idx);
        free(mat->vals);
        free(mat);
    }
}

// ============================================
// Timing Utilities
// ============================================

double get_time_ms() {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1000.0 + ts.tv_nsec / 1000000.0;
}

// ============================================
// Optimized Kernel
// ============================================

void spmv(const CSRMatrix* A, const double* x, double* y) {
    // Optimization: loop blocking (block_size=32)
    for (int i_block = 0; i_block < (A->rows + 31) / 32; i_block++) {
        int i_start = i_block * 32;
        int i_end = (i_start + 32 < A->rows) ? i_start + 32 : A->rows;
        for (int i = i_start; i < i_end; i++) {
            for (int p = A->row_ptr[i]; p < A->row_ptr[i + 1]; p++) {
                int j = A->col_idx[p];
                y[i] += A->vals[p] * x[j];
            }
        }
    }
}

// ============================================
// Reference Kernel (naive, for verification)
// ============================================

void spmv_reference(const CSRMatrix* A, const double* x, double* y) {
    for (int i = 0; i < A->rows; i++) {
        double sum = 0.0;
        for (int p = A->row_ptr[i]; p < A->row_ptr[i + 1]; p++) {
            int j = A->col_idx[p];
            sum += A->vals[p] * x[j];
        }
        y[i] = sum;
    }
}

// ============================================
// Main Function
// ============================================

int main(int argc, char** argv) {
    if (argc < 2) {
        fprintf(stderr, "Usage: %s <matrix.mtx> [iterations]\n", argv[0]);
        return 1;
    }

    int iterations = 100;
    if (argc >= 3) {
        iterations = atoi(argv[2]);
        if (iterations <= 0) {
            fprintf(stderr, "Error: iterations must be > 0\n");
            fprintf(stderr, "Usage: %s <matrix.mtx> [iterations]\n", argv[0]);
            return 1;
        }
    }

    // Deterministic initialization for reproducible benchmarks
    srand(42);

    // Load matrix
    CSRMatrix* A = load_matrix_market(argv[1]);
    if (!A) {
        fprintf(stderr, "Failed to load matrix\n");
        return 1;
    }

    // Allocate vectors
    double* x = (double*)malloc(A->cols * sizeof(double));
    double* y = (double*)malloc(A->rows * sizeof(double));
    double* y_ref = (double*)malloc(A->rows * sizeof(double));

    // Initialize x with random values
    for (int i = 0; i < A->cols; i++) {
        x[i] = (double)rand() / RAND_MAX;
    }
    memset(y, 0, A->rows * sizeof(double));
    memset(y_ref, 0, A->rows * sizeof(double));

    // Warmup
    spmv(A, x, y);

    // Benchmark with per-iteration timing
    double* iter_times = (double*)malloc(iterations * sizeof(double));

    for (int iter = 0; iter < iterations; iter++) {
        memset(y, 0, A->rows * sizeof(double));
        double iter_start = get_time_ms();
        spmv(A, x, y);
        double iter_end = get_time_ms();
        iter_times[iter] = iter_end - iter_start;
    }

    // Compute timing statistics
    double total_time = 0.0;
    double min_time = iter_times[0];
    double max_time = iter_times[0];
    for (int iter = 0; iter < iterations; iter++) {
        total_time += iter_times[iter];
        if (iter_times[iter] < min_time) min_time = iter_times[iter];
        if (iter_times[iter] > max_time) max_time = iter_times[iter];
    }
    double avg_time = total_time / iterations;

    // Compute standard deviation
    double variance = 0.0;
    for (int iter = 0; iter < iterations; iter++) {
        double diff = iter_times[iter] - avg_time;
        variance += diff * diff;
    }
    variance /= iterations;
    double stddev = sqrt(variance);
    double variance_pct = (avg_time > 0) ? (stddev / avg_time * 100.0) : 0.0;

    // Verify correctness
    spmv_reference(A, x, y_ref);
    double max_error = 0.0;
    for (int i = 0; i < A->rows; i++) {
        double err = y[i] - y_ref[i];
        if (err < 0) err = -err;
        if (err > max_error) max_error = err;
    }

    // Report results
    printf("Matrix: %s (%d x %d, %d nnz)\n", argv[1], A->rows, A->cols, A->nnz);
    printf("Iterations: %d\n", iterations);
    printf("Total time: %.2f ms\n", total_time);
    printf("Avg time per iteration: %.4f ms\n", avg_time);
    printf("Min time per iteration: %.4f ms\n", min_time);
    printf("Max time per iteration: %.4f ms\n", max_time);
    printf("Stddev time: %.4f ms\n", stddev);
    printf("Variance: %.2f%%\n", variance_pct);
    printf("Max error vs reference: %e\n", max_error);

    // Cleanup
    free(iter_times);
    free(x);
    free(y);
    free(y_ref);
    free_csr(A);

    return 0;
}
